  ),
}))

// Helper to create a minimal valid axis spec
const createMockAxisSpec = (): AxisSpecV1 => ({
  kind: 'cartesian',
  units: 10,
  grid: { enabled: true },
  axes: {
    showNumbers: true,
    showLabels: true,
    ticks: 1,
    labels: { x: 'x', y: 'y' },
    origin: { x: 0, y: 0 },
  },
  elements: { points: [], graphs: [], asymptotesVertical: [], asymptotesHorizontal: [] },
})

describe('MultiAxisRenderer', () => {
  const createProps = (overrides = {}) => ({
    blockId: 'test-block',
    graphs: [
      { id: 'g1', label: 'גרף 1', axis: createMockAxisSpec(), order: 1 },
      { id: 'g2', label: 'גרף 2', axis: createMockAxisSpec(), order: 2 },
    ],
    textPosition: 'above' as const,
    ...overrides,
  })

  it('renders correct number of AxisRenderer instances', () => {
    const props = createProps()
    render(<MultiAxisRenderer {...props} />)

    const axisRenderers = screen.getAllByTestId('axis-renderer')
    expect(axisRenderers).toHaveLength(2)
  })

  it('renders graphs sorted by order', () => {
    const props = createProps({
      graphs: [
        { id: 'g3', label: 'גרף 3', axis: createMockAxisSpec(), order: 3 },
        { id: 'g1', label: 'גרף 1', axis: createMockAxisSpec(), order: 1 },
        { id: 'g2', label: 'גרף 2', axis: createMockAxisSpec(), order: 2 },
      ],
    })
    render(<MultiAxisRenderer {...props} />)

    const axisRenderers = screen.getAllByTestId('axis-renderer')
    // Check order through DOM order
    expect(axisRenderers[0].getAttribute('data-block-id')).toBe('g1')
    expect(axisRenderers[1].getAttribute('data-block-id')).toBe('g2')
    expect(axisRenderers[2].getAttribute('data-block-id')).toBe('g3')
  })

  it('renders labels for each graph', () => {
    const props = createProps()
    render(<MultiAxisRenderer {...props} />)

    expect(screen.getByText('גרף 1')).toBeInTheDocument()
    expect(screen.getByText('גרף 2')).toBeInTheDocument()
  })

  it('renders prompt text above graphs when textPosition=above', () => {
    const props = createProps({
      prompt: {
        type: 'rich_text',
        format: 'md-math-v1',
        value: 'Compare the functions:',
      },
      textPosition: 'above',
    })
    render(<MultiAxisRenderer {...props} />)

    const richText = screen.getByTestId('rich-text')
    expect(richText).toBeInTheDocument()
    expect(richText.textContent).toBe('Compare the functions:')

    // Check order - prompt should come before axis renderers in DOM
    const container = screen.getByText('Compare the functions:').parentElement
    expect(container).toBeInTheDocument()
  })

  it('renders prompt text below graphs when textPosition=below', () => {
    const props = createProps({
      prompt: {
        type: 'rich_text',
        format: 'md-math-v1',
        value: 'Analysis:',
      },
      textPosition: 'below',
    })
    render(<MultiAxisRenderer {...props} />)

    expect(screen.getByText('Analysis:')).toBeInTheDocument()
  })

  it('applies full-width class for single graph', () => {
    const props = createProps({
      graphs: [{ id: 'g1', label: 'גרף 1', axis: createMockAxisSpec(), order: 1 }],
    })
    render(<MultiAxisRenderer {...props} />)

    const gridContainer = screen.getByText('גרף 1').parentElement?.parentElement
    expect(gridContainer).toHaveClass('grid-cols-1')
  })

  it('applies responsive grid classes for four graphs', () => {
    const props = createProps({
      graphs: [
        { id: 'g1', label: 'גרף 1', axis: createMockAxisSpec(), order: 1 },
        { id: 'g2', label: 'גרף 2', axis: createMockAxisSpec(), order: 2 },
        { id: 'g3', label: 'גרף 3', axis: createMockAxisSpec(), order: 3 },
        { id: 'g4', label: 'גרף 4', axis: createMockAxisSpec(), order: 4 },
      ],
    })
    render(<MultiAxisRenderer {...props} />)

    const gridContainer = screen.getByText('גרף 1').parentElement?.parentElement
    expect(gridContainer).toHaveClass('grid-cols-1', 'sm:grid-cols-2', 'lg:grid-cols-4')
  })
})

